import { useQuery, useQueryClient } from "@tanstack/react-query";
import { fetchTestimonialsApi } from "./api";
import type { TestimonialDto } from "./types";

export function useTestimonials(options?: { featured?: boolean }) {
  const featured = !!options?.featured;
  return useQuery({
    queryKey: ["testimonials", { featured }],
    queryFn: () => fetchTestimonialsApi(featured),
    staleTime: 10 * 60 * 1000, // 10m
    gcTime: 60 * 60 * 1000, // 60m
    retry: 1,
  });
}

export function useInvalidateTestimonials() {
  const qc = useQueryClient();
  return (featured?: boolean) =>
    qc.invalidateQueries({ queryKey: ["testimonials", { featured: !!featured }] });
}

export type { TestimonialDto };

